parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"transactionId": {
			"type": "string",
			"description": "Unique transaction identifier"
		},
		"revenueType": {
			"type": "string",
			"description": "Type of revenue (product, service, subscription, etc.)"
		},
		"taxCategory": {
			"type": "string",
			"description": "Applicable tax category (VAT, sales tax, exempt, etc.)"
		},
		"taxRate": {
			"type": "number",
			"description": "Tax rate percentage"
		},
		"amount": {
			"type": "number",
			"description": "Transaction amount"
		},
		"taxAmount": {
			"type": "number",
			"description": "Calculated tax amount"
		},
		"specialTreatment": {
			"type": "boolean",
			"description": "Whether special tax treatment is required"
		}
	}
}

{
	"type": "object",
	"properties": {
		"anomalies": {
			"type": "array",
			"description": "List of detected anomalies",
			"items": {
				"type": "object",
				"properties": {
					"transactionId": {
						"type": "string"
					},
					"anomalyType": {
						"type": "string",
						"description": "Type of anomaly (missing_invoice, incorrect_category, etc.)"
					},
					"severity": {
						"type": "string",
						"description": "Severity level (critical, high, medium, low)"
					},
					"description": {
						"type": "string",
						"description": "Detailed description of the issue"
					},
					"affectedAmount": {
						"type": "number",
						"description": "Transaction amount affected"
					}
				}
			}
		}
	}
}

{
	"type": "object",
	"properties": {
		"corrections": {
			"type": "array",
			"description": "List of corrections to apply",
			"items": {
				"type": "object",
				"properties": {
					"transactionId": {
						"type": "string"
					},
					"correctionType": {
						"type": "string",
						"description": "Type of correction needed"
					},
					"originalValue": {
						"type": "string",
						"description": "Original incorrect value"
					},
					"correctedValue": {
						"type": "string",
						"description": "Corrected value to apply"
					},
					"notes": {
						"type": "string",
						"description": "Explanation of why correction is needed"
					}
				}
			}
		}
	}
}

parameters.textBody:
=Tax Compliance Alert

{{ $json.summaryTitle }}

Anomalies Detected: {{ $json.anomaliesDetected }}
Corrections Applied: {{ $json.correctionsApplied }}
Sync Status: {{ $json.syncStatus }}

Full report sent via email.
